python -c "
import json
with open('/models/Qwen3.5-27B/model.safetensors.index.json') as f:
    idx = json.load(f)
wm = idx['weight_map']
# Count keys by layer and type
layers = {}
for k in wm.keys():
    if 'layers.' in k:
        parts = k.split('.')
        try:
            layer_idx = int(parts[parts.index('layers')+1])
            if layer_idx not in layers:
                layers[layer_idx] = []
            layers[layer_idx].append(k)
        except:
            pass
for li in sorted(layers.keys())[:4]:
    print(f'Layer {li}:')
    for k in sorted(layers[li]):
        print(f'  {k}')
"
